class Solution {
    public int minDays(int n) {
        int[] memo = new int[n + 1];
        return dfs(n, memo);
    }

    private int dfs(int n, int[] memo) {
        if (n <= 1) return n;
        if (memo[n] != 0) return memo[n];
        int res = 1 + Math.min(n % 2 + dfs(n / 2, memo), n % 3 + dfs(n / 3, memo));
        memo[n] = res;
        return res;
    }
}
